// src/pages/MyLeaves.js
import React from 'react';
import { useApp } from '../context/AppContext';

export default function MyLeaves({ setActivePage }) {
  const { leaveRequests, currentUser, staff } = useApp();

  const isAdmin = currentUser.role === 'admin';
  const myLeaves = isAdmin
    ? leaveRequests
    : leaveRequests.filter(r => r.teacherId === currentUser.id);

  const sorted = [...myLeaves].sort((a, b) => b.id - a.id);

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <div>
          <h1 style={styles.title}>{isAdmin ? '📋 All Leave History' : '📋 My Leaves'}</h1>
          <p style={styles.subtitle}>{sorted.length} total request(s)</p>
        </div>
        {!isAdmin && (
          <button style={styles.applyBtn} onClick={() => setActivePage('Apply Leave')}>
            + Apply for Leave
          </button>
        )}
      </div>

      {sorted.length === 0 ? (
        <div style={styles.empty}>
          <div style={styles.emptyIcon}>📭</div>
          <div style={styles.emptyText}>No leave requests yet</div>
          {!isAdmin && (
            <button style={styles.applyBtn} onClick={() => setActivePage('Apply Leave')}>
              Apply for Leave
            </button>
          )}
        </div>
      ) : (
        <div style={styles.list}>
          {sorted.map(req => (
            <LeaveCard key={req.id} req={req} isAdmin={isAdmin} />
          ))}
        </div>
      )}
    </div>
  );
}

function LeaveCard({ req, isAdmin }) {
  const [showSubs, setShowSubs] = React.useState(false);

  const statusConfig = {
    pending: { bg: '#fef9c3', border: '#fcd34d', label: '⏳ Pending', color: '#854d0e' },
    approved: { bg: '#dcfce7', border: '#86efac', label: '✅ Approved', color: '#14532d' },
    rejected: { bg: '#fee2e2', border: '#fca5a5', label: '❌ Rejected', color: '#7f1d1d' },
  };
  const sc = statusConfig[req.status] || statusConfig.pending;

  return (
    <div style={{ ...styles.card, borderLeft: `4px solid ${sc.border}`, background: sc.bg + 'aa' }}>
      <div style={styles.cardTop}>
        <div>
          {isAdmin && <div style={styles.adminName}>{req.teacherName}</div>}
          <div style={styles.dateRange}>
            📅 {req.fromDate} {req.toDate !== req.fromDate ? `→ ${req.toDate}` : '(1 day)'}
          </div>
          <div style={styles.reason}>📝 {req.reason}</div>
          <div style={styles.meta}>Applied on {req.createdAt} · {req.substituteRequests.length} class period(s) affected</div>
        </div>
        <div style={styles.statusSide}>
          <span style={{ ...styles.statusBadge, background: sc.bg, color: sc.color, border: `1px solid ${sc.border}` }}>
            {sc.label}
          </span>
          {req.substituteRequests.length > 0 && (
            <button style={styles.expandBtn} onClick={() => setShowSubs(!showSubs)}>
              {showSubs ? '▲ Hide Details' : '▼ View Substitutes'}
            </button>
          )}
        </div>
      </div>

      {showSubs && req.substituteRequests.length > 0 && (
        <div style={styles.subsSection}>
          <div style={styles.subsTitle}>Substitute Assignments</div>
          <div style={styles.subGrid}>
            {req.substituteRequests.map((sub, i) => {
              const subTeacher = sub.assignedTeacherId
                ? { name: `ID:${sub.assignedTeacherId}` }
                : null;
              return (
                <div key={i} style={styles.subCard}>
                  <div style={styles.subHeader}>
                    <span style={styles.subDay}>{sub.day}</span>
                    <span style={styles.subPeriod}>P{sub.period} · {sub.time}</span>
                  </div>
                  <div style={styles.subClass}>🏫 Class {sub.class}</div>
                  <div style={styles.subTeacher}>
                    {sub.assignedTeacherId
                      ? `👤 Substitute: ${sub.freeTeachers.find(t => t.id === sub.assignedTeacherId)?.name || 'Assigned'}`
                      : <span style={{ color: '#dc2626' }}>⚠️ No substitute assigned</span>
                    }
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
}

const styles = {
  container: { padding: 32, maxWidth: 900, margin: '0 auto' },
  header: { display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 28 },
  title: { fontSize: 28, fontWeight: 800, color: '#1e293b', margin: 0 },
  subtitle: { color: '#64748b', marginTop: 6, fontSize: 15 },
  applyBtn: {
    background: 'linear-gradient(135deg, #3b82f6, #1d4ed8)', color: '#fff',
    border: 'none', padding: '12px 24px', borderRadius: 12,
    cursor: 'pointer', fontSize: 14, fontWeight: 700,
  },
  empty: {
    background: '#f8fafc', borderRadius: 20, padding: 60,
    textAlign: 'center', display: 'flex', flexDirection: 'column',
    alignItems: 'center', gap: 16,
  },
  emptyIcon: { fontSize: 56 },
  emptyText: { color: '#94a3b8', fontSize: 16 },
  list: { display: 'flex', flexDirection: 'column', gap: 16 },
  card: {
    background: '#fff', borderRadius: 16, padding: 24,
    boxShadow: '0 2px 16px rgba(0,0,0,0.05)',
  },
  cardTop: { display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' },
  adminName: { fontWeight: 800, color: '#1e293b', fontSize: 16, marginBottom: 4 },
  dateRange: { fontWeight: 700, color: '#1d4ed8', fontSize: 15 },
  reason: { color: '#64748b', fontSize: 14, marginTop: 6 },
  meta: { color: '#94a3b8', fontSize: 12, marginTop: 4 },
  statusSide: { display: 'flex', flexDirection: 'column', alignItems: 'flex-end', gap: 8 },
  statusBadge: {
    padding: '6px 16px', borderRadius: 20,
    fontSize: 13, fontWeight: 700,
  },
  expandBtn: {
    background: '#f8fafc', border: '1px solid #e2e8f0',
    color: '#64748b', padding: '6px 14px', borderRadius: 10,
    cursor: 'pointer', fontSize: 12,
  },
  subsSection: { marginTop: 20, borderTop: '1px solid rgba(0,0,0,0.08)', paddingTop: 16 },
  subsTitle: { fontWeight: 700, color: '#374151', fontSize: 14, marginBottom: 12 },
  subGrid: { display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 12 },
  subCard: {
    background: 'rgba(255,255,255,0.8)', borderRadius: 12, padding: 14,
    border: '1px solid rgba(0,0,0,0.06)',
  },
  subHeader: { display: 'flex', justifyContent: 'space-between', marginBottom: 6 },
  subDay: { fontWeight: 700, color: '#1e293b', fontSize: 13 },
  subPeriod: { color: '#3b82f6', fontSize: 12, fontWeight: 600 },
  subClass: { color: '#64748b', fontSize: 13, marginBottom: 4 },
  subTeacher: { color: '#374151', fontSize: 13, fontWeight: 500 },
};
